mapper.select:
SELECT TICKET_ID , CLUSTER_NO , TICKET_TYPE , TO_CHAR(TICKET_GENERATION_TIME, 'YYYY-MM-DD HH24:MI:SS') AS TICKET_GENERATION_TIME , TO_CHAR(FAULT_TIME, 'YYYY-MM-DD HH24:MI:SS') AS FAULT_TIME , ROOT_CAUSE_TYPE , ROOT_CAUSE_CODE , ROOT_CAUSE_DOMAIN , TOTAL_RELATED_ALARM_CNT , STATUS , TICKET_RCA_RESULT_CODE , TICKET_RCA_RESULT_DTL_CODE , TICKET_RCA_RESULT_ORIG_DTL_CODE , ROOT_CAUSE_SYSNAMEA , ROOT_CAUSE_SYSNAMEZ , ROOT_CAUSE_PORTA , ROOT_CAUSE_PORTZ , NODE_NUM , NODE_NM , ALARMLOC , TO_CHAR(TICKET_UPDATE_TIME, 'YYYY-MM-DD HH24:MI:SS') AS TICKET_UPDATE_TIME , ZERO1_MODEL , ZERO1_ENTROPY , IP_ADDR FROM ( SELECT tc.TICKET_ID , CLUSTER_NO , TICKET_TYPE , TICKET_GENERATION_TIME , FAULT_TIME , ROOT_CAUSE_TYPE , ROOT_CAUSE_CODE , ROOT_CAUSE_DOMAIN , TOTAL_RELATED_ALARM_CNT , STATUS , TICKET_RCA_RESULT_CODE , TICKET_RCA_RESULT_DTL_CODE , TICKET_RCA_RESULT_ORIG_DTL_CODE , ROOT_CAUSE_SYSNAMEA , ROOT_CAUSE_SYSNAMEZ , ROOT_CAUSE_PORTA , ROOT_CAUSE_PORTZ , NULL NODE_NUM , NULL NODE_NM , NULL ALARMLOC , TICKET_UPDATE_TIME , ZERO1_MODEL , ZERO1_ENTROPY , NM.IP_ADDR AS IP_ADDR FROM rca.tb_rca_ticket_current TC INNER JOIN rca.tb_rca_ticket_al_current AL ON TC.TICKET_ID = AL.TICKET_ID LEFT OUTER JOIN resource.tb_node_mst NM ON NM.NODE_ID = al.root_cause_sysnamea WHERE TICKET_TYPE IN ('NFTT', 'FTT', 'ATT2', 'NTT') AND TC.PARENT_TICKET_ID IS NULL AND TC.TICKET_GENERATION_TIME > now() - INTERVAL '7' DAY UNION ALL SELECT ALARMNO AS TICKET_ID , NULL CLUSTER_NO , 'SYSLOG' TICKET_TYPE , ALARMTIME AS TICKET_GENERATION_TIME , NULL FAULT_TIME , NULL ROOT_CAUSE_TYPE , NULL ROOT_CAUSE_CODE , NULL ROOT_CAUSE_DOMAIN , NULL TOTAL_RELATED_ALARM_CNT , CASE WHEN sam.status IN ('INIT', 'FIN', 'AUTO_FIN') THEN sam.status ELSE '-' END AS STATUS , ALARMMSG AS TICKET_RCA_RESULT_CODE , ETC AS TICKET_RCA_RESULT_DTL_CODE , NULL TICKET_RCA_RESULT_ORIG_DTL_CODE , NULL ROOT_CAUSE_SYSNAMEA , NULL ROOT_CAUSE_SYSNAMEZ , NULL ROOT_CAUSE_PORTA , NULL ROOT_CAUSE_PORTZ , sam.NODE_NUM , sam.NODE_NM , sam.ALARMLOC , NULL TICKET_UPDATE_TIME , NULL ZERO1_MODEL , NULL ZERO1_ENTROPY , NM.IP_ADDR AS IP_ADDR FROM rca.tb_syslog_alarm_mst SAM LEFT OUTER JOIN resource.tb_node_mst NM ON NM.NODE_ID = SAM.NODE_NM WHERE SAM.ALARMTIME > now() - INTERVAL '48' HOUR ) T WHERE 1=1
AND TICKET_ID = #{TICKET_ID}
ORDER BY TICKET_GENERATION_TIME DESC, TICKET_ID desc

SELECT COALESCE(SUM(TRANS_PERF_CNT), 0)AS TRANS_PERF_CNT, COALESCE(SUM(TRANS_ALARM_CNT), 0)AS TRANS_ALARM_CNT, COALESCE(SUM(IP_RESOURCE_CNT), 0)AS IP_RESOURCE_CNT, COALESCE(SUM(IP_ALARM_CNT), 0)AS IP_ALARM_CNT, COALESCE(SUM(IP_PERF_CNT), 0)AS IP_PERF_CNT, COALESCE(SUM(IP_SFLOW_CNT), 0)AS IP_SFLOW_CNT, COALESCE(SUM(TICKET_RT_CNT), 0)AS TICKET_RT_CNT, COALESCE(SUM(TICKET_ATT_CNT), 0)AS TICKET_ATT_CNT, COALESCE(SUM(TICKET_NTT_CNT), 0)AS TICKET_NTT_CNT, COALESCE(SUM(TICKET_PF_CNT), 0)AS TICKET_PF_CNT, COALESCE(SUM(LINK_TOTAL_RESOURCE_CNT), 0) AS LINK_TOTAL_RESOURCE_CNT, COALESCE(SUM(LINK_TOTAL_ALARM_CNT), 0) AS LINK_TOTAL_ALARM_CNT, COALESCE(SUM(LINK_IP_PERF_CNT), 0) AS LINK_IP_PERF_CNT, COALESCE(SUM(LINK_TRANS_PERF_CNT), 0) AS LINK_TRANS_PERF_CNT FROM nia.tb_opsts WHERE 1=1
AND OPSTS_TIME = #{SEARCH_DATE}
AND OPSTS_GB = #{DATE_TYPE}

SELECT CASE WHEN tpd.SELF_PROCESS_TYPE = 'S' THEN tpd.ALARMNO ELSE tpd.TICKET_ID END AS TICKET_ID , TO_CHAR(OCCUR_TIME, 'YYYY-MM-DD HH24:MI:SS') AS OCCUR_TIME , TO_CHAR(CLOS_TIME, 'YYYY-MM-DD HH24:MI:SS') AS CLOS_TIME , CASE WHEN tpd.TICKET_TYPE IS NULL THEN 'SYSLOG' ELSE tpd.TICKET_TYPE END AS TICKET_TYPE , SELF_PROCESS_TYPE , CASE WHEN tpd.SELF_PROCESS_TYPE = 'S' THEN tss.FAULT_DETAIL_CONTENT ELSE ts.FAULT_DETAIL_CONTENT END AS FAULT_DETAIL_CONTENT , CLOS_TYPE , CLOS_STATUS , TO_CHAR(( SELECT FAULT_TIME FROM rca.tb_rca_ticket_current rtc WHERE rtc.ticket_id = tpd.ticket_id ), 'YYYY-MM-DD HH24:MI:SS') AS FAULT_TIME , TS.TICKET_RESULT , ( SELECT ZERO1_ENTROPY FROM rca.tb_rca_ticket_current rtc WHERE tpd.ticket_id = rtc.ticket_id ) ZERO1_ENTROPY FROM nia.tb_auto_treat_process_dtl tpd LEFT JOIN nia.tb_sop ts ON tpd.ticket_id = ts.ticket_id LEFT JOIN nia.tb_syslog_sop tss ON tpd.alarmno = tss.alarmno WHERE 1=1
AND DATE_TRUNC('MONTH', tpd.OCCUR_TIME) = TO_TIMESTAMP(CONCAT(#{DATE_TIME}, '-01'), 'YYYY-MM-DD')
AND tpd.OCCUR_TIME >= #{DATE_TIME}::TIMESTAMP AND tpd.OCCUR_TIME < #{DATE_TIME}::TIMESTAMP + ('1'||#{DATE_TYPE})::INTERVAL
AND tpd.SELF_PROCESS_GROUP = #{SELF_PROCESS_GROUP}
AND tpd.SELF_PROCESS_TYPE = #{SELF_PROCESS_TYPE}
AND tpd.CLOS_TYPE = #{CLOS_TYPE}
AND tpd.CLOS_STATUS = #{CLOS_STATUS}
ORDER BY TPD.OCCUR_TIME DESC

WITH DATEREGDATE_DATA AS ( SELECT DISTINCT DATEREGDATE FROM IP_YD.XE_SFLOW_LOG
AND DATEREGDATE BETWEEN #{FAULT_TIME}::TIMESTAMP - INTERVAL '1 HOUR' AND #{FAULT_TIME}::TIMESTAMP + INTERVAL '1 HOUR'
ORDER BY DATEREGDATE ) SELECT COLLECT_TIME , STRBYTES_COL , STRCOUNTS FROM ( SELECT CASE WHEN DD.DATEREGDATE = XSL.DATEREGDATE THEN XSL.STRBYTES_COL ELSE '0' END STRBYTES_COL , CASE WHEN DD.DATEREGDATE = XSL.DATEREGDATE THEN STRCOUNTS ELSE '0' END STRCOUNTS , DD.DATEREGDATE AS COLLECT_TIME FROM DATEREGDATE_DATA DD LEFT JOIN ( SELECT STRCOUNTS, STRBYTES_COL, DATEREGDATE FROM ip_yd.xe_sflow_log
AND DATEREGDATE = #{FAULT_TIME}::TIMESTAMP
AND STRSENDERIP = ( SELECT DISTINCT STRSENDERIP FROM RCA.TB_NOXIOUS_TRAFFIC WHERE TICKET_ID = #{TICKET_ID} )
AND STRS_IP = #{START_NODE}
AND STRS_PORT = #{START_PORT}
AND STRD_IP = #{END_NODE}
AND STRD_PORT = #{END_PORT}
) XSL ON 1=1 ) T GROUP BY COLLECT_TIME, STRBYTES_COL, STRCOUNTS

SELECT SYSLOG.ALARMNO , SYSLOG.NODE_NM , SYSLOG.NODE_NUM , SYSLOG.ALARMLOC , TO_CHAR(SYSLOG.ALARMTIME, 'YYYY-MM-DD HH24:MI:SS') AS ALARMTIME , SYSLOG.ALARMMSG , SYSLOG.ETC , SOP.PROC_STATUS , SOP.FAULT_CLASSIFY , SOP.FAULT_TYPE , SOP.FAULT_DETAIL_CONTENT , SOP.ETC_CONTENT , TO_CHAR(SOP.ALARM_OCCUR_TIME, 'YYYY-MM-DD HH24:MI:SS') AS ALARM_OCCUR_TIME , TO_CHAR(SOP.HANDLING_FIN_TIME, 'YYYY-MM-DD HH24:MI:SS') AS HANDLING_FIN_TIME , SOP.HANDLING_FIN_USER , SOP.STATUS FROM nia.tb_syslog_sop SOP INNER JOIN rca.tb_syslog_alarm_mst SYSLOG ON SOP.ALARMNO = SYSLOG.ALARMNO
AND SYSLOG.ALARMTIME > NOW() - INTERVAL '1' MONTH
AND SYSLOG.NODE_NM = #{NODE_NM}
AND SYSLOG.ALARMLOC = #{ALARMLOC}
AND SOP.STATUS = #{STATUS}
AND SOP.ALARM_OCCUR_TIME >= #{START_DATE}::TIMESTAMP
AND SOP.HANDLING_FIN_TIME <= #{END_DATE}::TIMESTAMP
ORDER BY SYSLOG.ALARMTIME DESC

